import React, { useEffect, useMemo, useRef, useState } from 'react';
import { PUZZLES } from './data/puzzles.js';
import {
  canAddBridge,
  canonicalBridgeKey,
  computeCurrentCounts,
  isVictory
} from './utils/hashiLogic.js';

const GRID = 40;
const W = 800;
const H = 600;

function isCtrlLike(e) {
  return e.ctrlKey || e.metaKey;
}

function findIslandAt(islands, x, y) {
  return islands.find((i) => i.x === x && i.y === y) || null;
}

function nextIslandInDirection(islands, from, dir) {
  const candidates = islands.filter((i) => i.id !== from.id);
  if (dir === 'left') {
    const sameRow = candidates.filter((i) => i.y === from.y && i.x < from.x);
    sameRow.sort((a, b) => b.x - a.x);
    return sameRow[0] || null;
  }
  if (dir === 'right') {
    const sameRow = candidates.filter((i) => i.y === from.y && i.x > from.x);
    sameRow.sort((a, b) => a.x - b.x);
    return sameRow[0] || null;
  }
  if (dir === 'up') {
    const sameCol = candidates.filter((i) => i.x === from.x && i.y < from.y);
    sameCol.sort((a, b) => b.y - a.y);
    return sameCol[0] || null;
  }
  if (dir === 'down') {
    const sameCol = candidates.filter((i) => i.x === from.x && i.y > from.y);
    sameCol.sort((a, b) => a.y - b.y);
    return sameCol[0] || null;
  }
  return null;
}

function cycleDelta(current) {
  // none -> single -> double -> none (delta based on current)
  if (current === 0) return +1;
  if (current === 1) return +1;
  return -2; // 2 -> 0
}

export default function App() {
  const [difficulty, setDifficulty] = useState('Easy');
  const puzzle = PUZZLES[difficulty];
  const islands = puzzle.islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null); // mouse selection
  const [cursorId, setCursorId] = useState(islands[0]?.id ?? null);
  const [kbdFromId, setKbdFromId] = useState(null); // keyboard selection (Enter)
  const [kbdDir, setKbdDir] = useState(null); // direction chosen after selecting
  const [error, setError] = useState(null);

  const svgRef = useRef(null);

  useEffect(() => {
    // when puzzle changes: reset bridges and selections
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
    setCursorId(PUZZLES[difficulty].islands[0]?.id ?? null);
    setKbdFromId(null);
    setKbdDir(null);
  }, [difficulty]);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function applyBridge(from, to, delta) {
    const res = canAddBridge(islands, bridges, from, to, delta);
    if (!res.valid) {
      setError(res.error);
      return false;
    }
    setError(null);
    const k = canonicalBridgeKey(from, to);
    const current = bridges.get(k) ?? 0;
    const next = current + delta;
    const nb = new Map(bridges);
    if (next === 0) nb.delete(k);
    else nb.set(k, next);
    setBridges(nb);
    return true;
  }

  function toggleCycle(from, to) {
    const k = canonicalBridgeKey(from, to);
    const current = bridges.get(k) ?? 0;
    const delta = cycleDelta(current);
    applyBridge(from, to, delta);
  }

  function toggleRightClick(from, to) {
    const k = canonicalBridgeKey(from, to);
    const current = bridges.get(k) ?? 0;
    const delta = current > 0 ? -1 : +1;
    applyBridge(from, to, delta);
  }

  function onIslandClick(isl, e) {
    e.preventDefault();
    svgRef.current?.focus();

    setCursorId(isl.id);

    if (selectedId == null) {
      setSelectedId(isl.id);
      return;
    }
    if (selectedId === isl.id) {
      // clicking same island just keeps it selected
      return;
    }

    const from = islands.find((i) => i.id === selectedId);
    const to = isl;
    if (e.type === 'click' && (e.button === 0)) {
      // second click toggles
      toggleCycle(from, to);
      setSelectedId(null);
    }
  }

  function onIslandContextMenu(isl, e) {
    e.preventDefault();
    svgRef.current?.focus();

    if (selectedId == null || selectedId === isl.id) {
      setSelectedId(isl.id);
      return;
    }
    const from = islands.find((i) => i.id === selectedId);
    const to = isl;
    toggleRightClick(from, to);
    setSelectedId(null);
  }

  function onIslandAuxOrCtrlClick(isl, e) {
    // Ctrl+click should behave like right click toggle
    if (e.type === 'click' && isCtrlLike(e)) {
      e.preventDefault();
      svgRef.current?.focus();
      if (selectedId == null || selectedId === isl.id) {
        setSelectedId(isl.id);
        return;
      }
      const from = islands.find((i) => i.id === selectedId);
      toggleRightClick(from, isl);
      setSelectedId(null);
    }
  }

  function handleKeyDown(e) {
    if (!['ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown', 'Enter', 'Escape'].includes(e.key)) return;
    e.preventDefault();

    const cursor = islands.find((i) => i.id === cursorId) || islands[0];
    if (!cursor) return;

    if (e.key === 'Escape') {
      setKbdFromId(null);
      setKbdDir(null);
      setSelectedId(null);
      setError(null);
      return;
    }

    if (e.key.startsWith('Arrow')) {
      const dir =
        e.key === 'ArrowLeft' ? 'left' :
        e.key === 'ArrowRight' ? 'right' :
        e.key === 'ArrowUp' ? 'up' : 'down';

      if (kbdFromId != null) {
        // after selecting an island with Enter: arrows choose direction; move cursor along that direction
        setKbdDir(dir);
      }

      const next = nextIslandInDirection(islands, cursor, dir);
      if (next) setCursorId(next.id);
      return;
    }

    if (e.key === 'Enter') {
      if (kbdFromId == null) {
        // first Enter selects starting island
        setKbdFromId(cursor.id);
        setSelectedId(cursor.id);
        return;
      }

      // second Enter attempts toggle between from and cursor (must be different)
      const from = islands.find((i) => i.id === kbdFromId);
      const to = cursor;
      if (!from || !to || from.id === to.id) return;

      // toggle cycle
      const ok = (function () {
        const k = canonicalBridgeKey(from, to);
        const current = bridges.get(k) ?? 0;
        const delta = cycleDelta(current);
        return applyBridge(from, to, delta);
      })();

      if (ok) {
        setKbdFromId(null);
        setKbdDir(null);
        setSelectedId(null);
      }
    }
  }

  function reset() {
    setBridges(new Map());
    setSelectedId(null);
    setKbdFromId(null);
    setKbdDir(null);
    setError(null);
    svgRef.current?.focus();
  }

  // render bridges
  const bridgeLines = [];
  for (const [k, n] of bridges.entries()) {
    if (!n) continue;
    const [x1, y1, x2, y2] = k.split(',').map(Number);
    const ax = x1 * GRID;
    const ay = y1 * GRID;
    const bx = x2 * GRID;
    const by = y2 * GRID;

    const isH = ay === by;
    const offset = 6;

    if (n === 1) {
      bridgeLines.push(
        <line
          key={`b-${k}-1`}
          x1={ax}
          y1={ay}
          x2={bx}
          y2={by}
          stroke="#00ff66"
          strokeWidth={4}
          strokeLinecap="round"
        />
      );
    } else if (n === 2) {
      const dx = isH ? 0 : offset;
      const dy = isH ? offset : 0;
      bridgeLines.push(
        <line
          key={`b-${k}-2a`}
          x1={ax - dx}
          y1={ay - dy}
          x2={bx - dx}
          y2={by - dy}
          stroke="#00ff66"
          strokeWidth={4}
          strokeLinecap="round"
        />
      );
      bridgeLines.push(
        <line
          key={`b-${k}-2b`}
          x1={ax + dx}
          y1={ay + dy}
          x2={bx + dx}
          y2={by + dy}
          stroke="#00ff66"
          strokeWidth={4}
          strokeLinecap="round"
        />
      );
    }
  }

  const cursor = islands.find((i) => i.id === cursorId) || islands[0];
  const cursorPx = cursor ? { x: cursor.x * GRID, y: cursor.y * GRID } : { x: 0, y: 0 };

  return (
    <div className="app">
      <div className="hud">
        <label>
          Puzzle
          <select value={difficulty} onChange={(e) => setDifficulty(e.target.value)}>
            <option value="Easy">Easy</option>
            <option value="Medium">Medium</option>
            <option value="Hard">Hard</option>
          </select>
        </label>
        <button onClick={reset}>Reset</button>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg
        ref={svgRef}
        width={W}
        height={H}
        viewBox={`0 0 ${W} ${H}`}
        style={{ display: 'block', position: 'absolute', top: 0, left: 0, background: '#000' }}
        tabIndex={0}
        onKeyDown={handleKeyDown}
      >
        {/* cursor (must not be a circle) */}
        {cursor ? (
          <rect
            x={cursorPx.x - 18}
            y={cursorPx.y - 18}
            width={36}
            height={36}
            fill="none"
            stroke="#00ff66"
            strokeWidth={3}
            strokeDasharray="6 4"
          />
        ) : null}

        {/* bridges under islands */}
        <g>{bridgeLines}</g>

        {/* islands */}
        <g>
          {islands.map((isl) => {
            const px = isl.x * GRID;
            const py = isl.y * GRID;
            const isSelected = selectedId === isl.id || kbdFromId === isl.id;
            const current = counts.get(isl.id) ?? 0;
            const satisfied = current === isl.value;

            return (
              <g key={isl.id}>
                <circle
                  cx={px}
                  cy={py}
                  r={16}
                  fill="#000"
                  stroke={isSelected ? '#00ff66' : 'rgba(0,255,102,0.7)'}
                  strokeWidth={isSelected ? 4 : 2}
                  onClick={(e) => {
                    onIslandAuxOrCtrlClick(isl, e);
                    if (!isCtrlLike(e)) onIslandClick(isl, e);
                  }}
                  onContextMenu={(e) => onIslandContextMenu(isl, e)}
                />
                <text
                  x={px}
                  y={py + 6}
                  textAnchor="middle"
                  fontSize="16"
                  fill={satisfied ? '#00ff66' : 'rgba(0,255,102,0.9)'}
                >
                  {isl.value}
                </text>
              </g>
            );
          })}
        </g>
      </svg>
    </div>
  );
}
